import{_ as t,c as o,o as a,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Changelog: Version History | opencode-md-table-formatter","description":"Track the version evolution of opencode-md-table-formatter. Learn about new features, fixes, and technical details in each release.","frontmatter":{"title":"Changelog: Version History | opencode-md-table-formatter","sidebarTitle":"Changelog","subtitle":"Changelog: Version History | opencode-md-table-formatter","description":"Track the version evolution of opencode-md-table-formatter. Learn about new features, fixes, and technical details in each release.","tags":["changelog","version-history","release-notes"],"prerequisite":[],"order":90},"headers":[],"relativePath":"franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),r={name:"franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function i(l,e,s,d,c,g){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="changelog-version-history-and-release-notes" tabindex="-1">Changelog: Version History and Release Notes <a class="header-anchor" href="#changelog-version-history-and-release-notes" aria-label="Permalink to &quot;Changelog: Version History and Release Notes&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">What You&#39;ll Learn</p><ul><li>Track the plugin&#39;s version evolution</li><li>Understand new features and fixes in each version</li><li>Master known limitations and technical details</li><li>Learn about potential future enhancements</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><p>This is the <strong>initial release</strong> of opencode-md-table-formatter, including the following core features:</p><ul><li><strong>Automatic Table Formatting</strong>: Automatically format AI-generated Markdown tables via the <code>experimental.text.complete</code> hook</li><li><strong>Concealment Mode Support</strong>: Correctly handle hidden Markdown symbols (like <code>**</code>, <code>*</code>) when calculating widths</li><li><strong>Nested Markdown Processing</strong>: Support Markdown syntax at any nesting depth using multi-pass stripping algorithm</li><li><strong>Code Block Protection</strong>: Markdown symbols within inline code (<code>`code`</code>) remain in literal form and don&#39;t participate in width calculation</li><li><strong>Alignment Support</strong>: Support left alignment (<code>---</code> or <code>:---</code>), center alignment (<code>:---:</code>), right alignment (<code>---:</code>)</li><li><strong>Width Caching Optimization</strong>: Cache string display width calculation results to improve performance</li><li><strong>Invalid Table Validation</strong>: Automatically validate table structure, invalid tables will have error comments added</li><li><strong>Multi-character Support</strong>: Support Emoji, Unicode characters, empty cells, and overly long content</li><li><strong>Silent Error Handling</strong>: Formatting failures won&#39;t interrupt the OpenCode workflow</li></ul><h3 id="technical-details" tabindex="-1">Technical Details <a class="header-anchor" href="#technical-details" aria-label="Permalink to &quot;Technical Details&quot;">​</a></h3><p>This version includes approximately <strong>230 lines of production-ready TypeScript code</strong>:</p><ul><li><strong>12 Functions</strong>: Clear responsibilities, well-separated</li><li><strong>Type Safety</strong>: Proper use of the <code>Hooks</code> interface</li><li><strong>Smart Cache Cleanup</strong>: Triggered when operation count exceeds 100 or cache entries exceed 1000</li><li><strong>Multi-pass Regex Processing</strong>: Support Markdown symbol stripping at arbitrary nesting depths</li></ul><div class="tip custom-block"><p class="custom-block-title">Cache Mechanism</p><p>The cache is designed to optimize width calculations for repeated content. For example, when the same cell text appears multiple times in a table, the width is calculated only once, and subsequent reads retrieve it directly from the cache.</p></div><h3 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h3><p>This version does not support the following scenarios:</p><ul><li><strong>HTML Tables</strong>: Only supports Markdown pipe tables</li><li><strong>Multi-line Cells</strong>: Cells containing <code>&lt;br&gt;</code> tags are not supported</li><li><strong>Tables Without Separator Rows</strong>: Tables must include a separator row (<code>|---|</code>) to be formatted</li><li><strong>Dependency Requirements</strong>: Requires <code>@opencode-ai/plugin</code> &gt;= 0.13.7 (uses the undocumented <code>experimental.text.complete</code> hook)</li></ul><div class="info custom-block"><p class="custom-block-title">Version Requirements</p><p>The plugin requires OpenCode &gt;= 1.0.137 and <code>@opencode-ai/plugin</code> &gt;= 0.13.7 to work properly.</p></div><hr><h2 id="future-plans" tabindex="-1">Future Plans <a class="header-anchor" href="#future-plans" aria-label="Permalink to &quot;Future Plans&quot;">​</a></h2><p>The following features are planned for future versions:</p><ul><li><strong>Configuration Options</strong>: Support custom minimum/maximum column widths, disable specific features</li><li><strong>Headerless Table Support</strong>: Format tables without header rows</li><li><strong>Performance Optimization</strong>: Performance analysis and optimization for very large tables (100+ rows)</li><li><strong>More Alignment Options</strong>: Extend alignment syntax and functionality</li></ul><div class="tip custom-block"><p class="custom-block-title">Contribute</p><p>If you have feature suggestions or want to contribute code, feel free to share your ideas in <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a>.</p></div><hr><h2 id="changelog-format-explanation" tabindex="-1">Changelog Format Explanation <a class="header-anchor" href="#changelog-format-explanation" aria-label="Permalink to &quot;Changelog Format Explanation&quot;">​</a></h2><p>This project&#39;s changelog follows the <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a> format, and version numbers follow <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><p><strong>Version Format</strong>: <code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>: Incompatible API changes</li><li><strong>MINOR</strong>: Backwards-compatible new features</li><li><strong>PATCH</strong>: Backwards-compatible bug fixes</li></ul><p><strong>Change Types</strong>:</p><ul><li><strong>Added</strong>: New features</li><li><strong>Changed</strong>: Changes to existing features</li><li><strong>Deprecated</strong>: Features to be removed</li><li><strong>Removed</strong>: Removed features</li><li><strong>Fixed</strong>: Bug fixes</li><li><strong>Security</strong>: Security-related fixes</li></ul><hr><h2 id="recommended-reading-order" tabindex="-1">Recommended Reading Order <a class="header-anchor" href="#recommended-reading-order" aria-label="Permalink to &quot;Recommended Reading Order&quot;">​</a></h2><p>If you&#39;re a new user, we recommend learning in the following order:</p><ol><li><a href="./../../start/getting-started/">Quick Start: Installation and Configuration</a> — Get started quickly</li><li><a href="./../../start/features/">Features Overview: The Magic of Automatic Formatting</a> — Understand core features</li><li><a href="./../../faq/troubleshooting/">FAQ: What to Do When Tables Aren&#39;t Formatted</a> — Troubleshooting</li><li><a href="./../../appendix/limitations/">Known Limitations: Where Are the Plugin&#39;s Boundaries</a> — Understand limitations</li></ol>',31)])])}const p=t(r,[["render",i]]);export{h as __pageData,p as default};
